export const NOImg = 'data:image/png;base64,'

export const convertBase64ToBlob = (base64Image) => {
    var base64Data = base64Image.replace(/^data:image\/(png|jpg|jpeg);base64,/, '');

    // Convert the base64 data to a binary string
    var binaryString = atob(base64Data);

    // Create a Uint8Array from the binary string
    var uint8Array = new Uint8Array(binaryString.length);
    for (var i = 0; i < binaryString.length; i++) {
        uint8Array[i] = binaryString.charCodeAt(i);
    }

    // Create a Blob from the Uint8Array
    var blob = new Blob([uint8Array], { type: 'image/png' });

    // Now you have the image data as a Blob
    return blob;
}
